bool Present_Accelerometer(const void* p, int fid) {
  const auto& e = *static_cast<const Accelerometer*>(p);
  (void)e;
  switch (fid) {
    case 0: return e.name.has_value();
    case 1: return e.site.has_value();
    case 2: return e.nsample.has_value();
    case 3: return e.interp.has_value();
    case 4: return e.delay.has_value();
    case 5: return e.interval.has_value();
    case 6: return e.cutoff.has_value();
    case 7: return e.noise.has_value();
    case 8: return e.user.has_value();
    default: return false;
  }
}
